Bash(node -e "
const fs = require\('fs'\);
const path = require\('path'\);
const dir = 'public/js';
const files = fs.readdirSync\(dir\).filter\(f => f.endsWith\('.js'\)\);
const exportMap = {};

for \(const f of files\) {
  const content = fs.readFileSync\(path.join\(dir, f\), 'utf8'\);
  const exports = [];
  for \(const m of content.matchAll\(/export\\s+\(?:function|const|let|var\)\\s+\(\\w+\)/g\)\) {
    exports.push\(m[1]\);
  }
  exportMap[f] = exports;
}

// Collect all imported names per source file
const issues = [];
for \(const f of files\) {
  const content = fs.readFileSync\(path.join\(dir, f\), 'utf8'\);
  // Match all import specifiers from ./xxx.js
  for \(const m of content.matchAll\(/import\\s+\\{\([^}]+\)\\}\\s+from\\s+\\"\\.\\/\(\\w+\)\\.js\\"/gs\)\) {
    const rawNames = m[1];
    const from = m[2] + '.js';
    const names = rawNames.split\(','\).map\(s => s.trim\(\)\).filter\(s => s.length > 0\);
    for \(const name of names\) {
      if \(exportMap[from] && exportMap[from].indexOf\(name\) === -1\) {
        issues.push\(name + ' from ' + from + ' \(in ' + f + '\)'\);
      }
    }
  }
}
if \(issues.length === 0\) console.log\('All imports verified OK'\);
else issues.forEach\(i => console.log\('MISSING:', i\)\);
")
